import { Hono } from 'hono';
import { deleteFileAsync } from '../services/fileService';

const app = new Hono();

app.delete('/files/:id', async (c) => {
  const fileId = c.req.param('id');

  try {
    // Remove the row from the database
    await deleteFileFromDatabase(fileId);

    // Delete the underlying object asynchronously
    await deleteFileAsync(fileId);

    // Emit file.deleted event
    emitEvent('file.deleted', { fileId });

    return c.json({ message: 'File deleted successfully' }, 200);
  } catch (error) {
    console.error(error);
    return c.json({ error: 'Failed to delete file' }, 500);
  }
});

